# Example: Aggregating use-case registry metrics by stage

from collections import Counter

def summarise_use_case_registry(registry: list[dict]) -> dict:
    """
    registry: list of {
        "id": str,
        "stage": "idea" | "prototype" | "pilot" | "production",
        "business_unit": str,
        "estimated_hours_saved_per_week": float | None
    }
    """
    stage_counts = Counter(r["stage"] for r in registry)
    by_unit: dict[str, list] = {}
    for r in registry:
        by_unit.setdefault(r["business_unit"], []).append(r)

    total_hours_saved = sum(
        r["estimated_hours_saved_per_week"] or 0
        for r in registry
        if r["stage"] == "production"
    )

    return {
        "total_use_cases": len(registry),
        "by_stage": dict(stage_counts),
        "by_business_unit": {k: len(v) for k, v in by_unit.items()},
        "weekly_hours_saved_in_production": round(total_hours_saved, 1),
    }

# Sample output:
